# -*- coding: utf-8 -*-
"""Bolalar jismoniy tarbiyasi - mustaqil ishlar to'plami.
Har bir mavzu ~12 A4 sahifa. Times New Roman 14pt, 1.5 interval."""
import zipfile, datetime

TOPICS = []

def esc(t):
    return t.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace('"', "&quot;")

def run(text, bold=False, size=28, font="Times New Roman"):
    rpr = '<w:rPr><w:rFonts w:ascii="%s" w:hAnsi="%s" w:cs="%s"/>' % (font, font, font)
    if bold:
        rpr += '<w:b/><w:bCs/>'
    rpr += '<w:sz w:val="%d"/><w:szCs w:val="%d"/></w:rPr>' % (size, size)
    return '<w:r>%s<w:t xml:space="preserve">%s</w:t></w:r>' % (rpr, esc(text))

def para(text, bold=False, size=28, align="both", indent_first=709, space_after=280, line=408, keep_next=False):
    ppr = '<w:pPr>'
    if keep_next:
        ppr += '<w:keepNext/>'
    ppr += '<w:spacing w:after="%d" w:line="%d" w:lineRule="auto"/>' % (space_after, line)
    if indent_first:
        ppr += '<w:ind w:firstLine="%d"/>' % indent_first
    ppr += '<w:jc w:val="%s"/></w:pPr>' % align
    return '<w:p>%s%s</w:p>' % (ppr, run(text, bold=bold, size=size))

def page_break():
    return '<w:p><w:r><w:br w:type="page"/></w:r></w:p>'

def empty_para():
    return '<w:p><w:pPr><w:spacing w:after="0" w:line="408" w:lineRule="auto"/></w:pPr></w:p>'

def build_topic(t, is_first):
    parts = []
    if not is_first:
        parts.append(page_break())
    parts.append(para("%d-MAVZU. %s" % (t["num"], t["title"].upper()), bold=True, size=30, align="center", indent_first=0, space_after=180, keep_next=True))
    parts.append(para("Reja:", bold=True, size=28, align="left", indent_first=0, space_after=60, keep_next=True))
    for i, r in enumerate(t["reja"], 1):
        parts.append(para("%d. %s" % (i, r), size=28, align="left", indent_first=360, space_after=80))
    parts.append(empty_para())
    parts.append(empty_para())
    for idx, (head, paras) in enumerate(t["sections"], 1):
        parts.append(empty_para())
        parts.append(para("%d. %s" % (idx, head), bold=True, size=28, align="left", indent_first=0, space_after=80, keep_next=True))
        for p in paras:
            parts.append(para(p, size=28, align="both", indent_first=709, space_after=200))
    # Xulosa
    parts.append(empty_para())
    parts.append(para("Xulosa", bold=True, size=28, align="left", indent_first=0, space_after=80, keep_next=True))
    parts.append(para("Ushbu mavzuni o\u2018rganish natijasida \"%s\" haqida mukammal bilimga ega bo\u2018ldik. Mavzuda ko\u2018rib chiqilgan masalalar bolalar jismoniy tarbiyasi nazariyasi va amaliyotining muhim qismlarini tashkil etadi. Olingan bilimlar bo\u2018lajak mutaxassislarning kasbiy faoliyatida muhim ahamiyat kasb etadi va ularning pedagogik mahoratini oshirishga xizmat qiladi." % t["title"], size=28, align="both", indent_first=709, space_after=200))
    parts.append(para("Mavzu doirasida o\u2018rganilgan nazariy ma\u2019lumotlar va amaliy tavsiyalar maktabgacha ta\u2019lim muassasalarida jismoniy tarbiya jarayonini to\u2018g\u2018ri tashkil etish uchun zarur bilim bazasini yaratadi. Har bir tarbiyachi bu bilimlarni o\u2018z amaliyotida qo\u2018llab, bolalarning sog\u2018lom va barkamol rivojlanishiga hissa qo\u2018shishi lozim. Shu bilan birga, doimiy o\u2018z ustida ishlash va yangi ilmiy yutuqlarni o\u2018rganish mutaxassisning kasbiy o\u2018sishi uchun muhim shartdir.", size=28, align="both", indent_first=709, space_after=200))
    parts.append(para("Bolalar jismoniy tarbiyasi sohasidagi bilimlarni chuqur egallash va amaliyotda mohirona qo\u2018llash yosh avlodning sog\u2018lom, baquvvat va har tomonlama rivojlangan shaxs sifatida voyaga yetishining muhim kafolati hisoblanadi. Shuning uchun ushbu mavzudagi bilimlar kelajakdagi pedagogik faoliyatimizning mustahkam poydevorini tashkil etadi.", size=28, align="both", indent_first=709, space_after=200))
    # Adabiyotlar
    parts.append(empty_para())
    parts.append(para("Foydalanilgan adabiyotlar", bold=True, size=28, align="left", indent_first=0, space_after=80, keep_next=True))
    refs = [
        "Xo\u2018jayev F.X. Bolalar jismoniy tarbiyasi nazariyasi va metodikasi. \u2013 T.: O\u2018qituvchi, 2020.",
        "Abdullayev A., Xonkeldiyev Sh. Maktabgacha yoshdagi bolalar jismoniy tarbiyasi. \u2013 T.: Fan va texnologiya, 2019.",
        "Yunusova D.I. Bolalar jismoniy madaniyati va sport. \u2013 T.: Navoiy universiteti, 2021.",
        "O\u2018zbekiston Respublikasi \"Maktabgacha ta\u2019lim to\u2018g\u2018risida\"gi Qonuni. \u2013 T., 2019.",
        "\"Ilk qadam\" Davlat o\u2018quv dasturi. \u2013 T.: Maktabgacha ta\u2019lim vazirligi, 2018.",
        "Stepanyenkova E.Ya. Maktabgacha yoshdagi bolalar jismoniy tarbiyasi nazariyasi va metodikasi. \u2013 M.: Akademiya, 2018.",
        "Ilk va maktabgacha yoshdagi bolalar rivojlanishiga qo\u2018yiladigan Davlat talablari. \u2013 T., 2018.",
        "Keneman A.V., Xuxlayeva D.V. Maktabgacha yoshdagi bolalar jismoniy tarbiyasi nazariyasi va metodikasi. \u2013 M.: Prosvesheniye, 2017.",
    ]
    for i, ref in enumerate(refs, 1):
        parts.append(para("%d. %s" % (i, ref), size=28, align="both", indent_first=0, space_after=100))
    return "".join(parts)

def build_document():
    body = "".join(build_topic(t, i == 0) for i, t in enumerate(TOPICS))
    sect = '<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1134" w:right="850" w:bottom="1134" w:left="1701" w:header="708" w:footer="708" w:gutter="0"/><w:pgNumType w:start="1"/></w:sectPr>'
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><w:body>' + body + sect + '</w:body></w:document>'

CT = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/><Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-package.core-properties+xml"/><Override PartName="/docProps/app.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/></Types>'
RE = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/><Relationship Id="rId2" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/><Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/></Relationships>'
DR = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/></Relationships>'
ST = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/><w:lang w:val="uz-Latn-UZ"/></w:rPr></w:rPrDefault><w:pPrDefault><w:pPr><w:spacing w:line="408" w:lineRule="auto"/></w:pPr></w:pPrDefault></w:docDefaults><w:style w:type="paragraph" w:default="1" w:styleId="Normal"><w:name w:val="Normal"/><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:style></w:styles>'

def cp():
    n = datetime.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>Bolalar jismoniy tarbiyasi - mustaqil ishlar</dc:title><dc:creator>Mustaqil ish</dc:creator><dcterms:created xsi:type="dcterms:W3CDTF">%s</dcterms:created><dcterms:modified xsi:type="dcterms:W3CDTF">%s</dcterms:modified></cp:coreProperties>' % (n, n)

AP = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties"><Application>Mustaqil ish</Application></Properties>'

def write_docx(path):
    with zipfile.ZipFile(path, "w", zipfile.ZIP_DEFLATED) as z:
        z.writestr("[Content_Types].xml", CT)
        z.writestr("_rels/.rels", RE)
        z.writestr("word/document.xml", build_document())
        z.writestr("word/_rels/document.xml.rels", DR)
        z.writestr("word/styles.xml", ST)
        z.writestr("docProps/core.xml", cp())
        z.writestr("docProps/app.xml", AP)
    print("OK:", path, "|", len(TOPICS), "mavzu")



